"""
MKT Original Language Commentary — Psalms chapters 62–67
Run: python3 scripts/zc-original-psalms-62-67.py

Key decisions:
- Ps 62: dûmîyāh = expectant silence (not despair); the refrain differs v2 vs v6 (meʾōd omitted
  = stronger confidence in v6); the "one/two" numerical oracle (v11-12) — wisdom-speech form;
  ḥesed and ʿōz as the two divine attributes declared in v11-12
- Ps 63: kāmap (hapax) = to long/yearn intensely; ḥesed ṭôb mêḥayyîm = steadfast love better
  than life; dābaq (v8) = the cleaving-word of Gen 2:24 marriage covenant
- Ps 64: the double irony — God shoots his own arrow at those who shoot arrows; their tongue
  becomes their downfall (v7-8)
- Ps 65: dûmîyāh as praise (v1 — silence as the highest worship before God); kol-bāśār (all flesh)
  in v2; the nature-poem of God as farmer (vv9-13) — the year crowned like a king
- Ps 66: Exodus + Jordan crossing (v6); silver-refining testing (v10); the heart-integrity
  condition for answered prayer (v18-19); the pivot from communal hymn to personal testimony (v13+)
- Ps 67: Aaronic blessing (Num 6:24-26) universalized — Israel's blessing becomes the instrument
  of earth-wide divine-way proclamation; the harvest (v6) as eschatological sign
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-original for Psalms 62–67 — the expectant-silence trust psalm (Ps62),
#   the wilderness-thirst psalm with ḥesed-better-than-life (Ps63), the secret-arrow
#   conspiracy and divine reversal (Ps64), the harvest-and-universal-approach psalm
#   (Ps65), the Exodus/testing/personal-testimony psalm (Ps66), and the Aaronic
#   blessing universalized (Ps67).
# CHANGE? If data/commentary/mkt-original/psalms.json structure changes, update
#   load_comm/save_comm per Z_COMMENTARY_SCRIPT_GUIDE.md.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-original/psalms.json')); print([len(d.get(str(c),{})) for c in range(62,68)])"

PSALMS = {
  "62": {
    "1": '<p>Psalm 62 is attributed to Jeduthun — one of David\'s chief musicians (1 Chr 16:41-42; 25:1-6). <strong>אַךְ אֶל-אֱלֹהִים דּוּמִיָּה נַפְשִׁי</strong> (<em>ʾak ʾel-ʾĕlōhîm dûmiyyāh napshî</em>, "Truly my soul waits in silence for God alone") — <em>ʾak</em>: truly, surely (a strong affirmation-particle); <em>dûmiyyāh</em>: silence, stillness (from <em>dāmam</em>: to be still, to be silent — not the silence of despair or death but of deliberate, attentive waiting; the soldier "at ease" who has stopped striving). <em>Napshî</em>: my soul (the whole animated self) — the entire person oriented toward God alone. <strong>מִמֶּנּוּ יְשׁוּעָתִי</strong> (<em>mimmennû yĕshûʿātî</em>, "from him comes my salvation") — the salvation (<em>yĕshûʿāh</em>) originates exclusively from God: the preposition <em>min</em> (from) specifies the single source. The psalm\'s entire theology: God alone as the sole ground of trust.</p>',
    "2": '<p><strong>אַךְ-הוּא צוּרִי וִישׁוּעָתִי מִשְׂגַּבִּי</strong> (<em>ʾak-hûʾ ṣûrî wîshûʿātî miśgabbî</em>, "He alone is my rock and my salvation; he is my fortress") — the triple confession: <em>ṣûr</em> (rock — the immovable foundation), <em>yĕshûʿāh</em> (salvation — the rescue), <em>miśgāb</em> (fortress — the elevated stronghold of Ps 46:7). <strong>לֹא-אֶמּוֹט רַבָּה</strong> (<em>lōʾ-ʾemmôṭ rabbāh</em>, "I will not be greatly shaken") — <em>māṭ</em>: to totter, to slip; <em>rabbāh</em>: greatly, much. The qualifier "greatly" (<em>rabbāh</em>) is the first refrain\'s humility: the Psalmist does not claim immunity from all shaking, only that the shaking will not be total. Compare v6 where <em>rabbāh</em> is absent — a stronger confidence reached by the psalm\'s end.</p>',
    "3": '<p><strong>עַד-אָנָה תְּהוֹתְתוּ עַל-אִישׁ</strong> (<em>ʿad-ʾānāh tĕhôtĕtû ʿal-ʾîsh</em>, "How long will all of you assault a man?") — <em>ʿad-ʾānāh</em>: "until when?" — the protest against prolonged oppression. <em>Hātat</em> (polel/hithpolel: to attack, to rush upon): the violent pressing assault. <strong>תְּרָצְּחוּ כֻּלְּכֶם</strong> (<em>tĕrāṣĕḥû kullĕkem</em>, "you might as well be killing him") — <em>rāṣaḥ</em>: to murder; the hyperbole of sustained persecution: the relentless assault amounts to murder. <strong>כְּקִיר נָטוּי כְּגָדֵר הַדְּחוּיָה</strong> (<em>kĕqîr nāṭûy kĕgādêr haddĕḥûyāh</em>, "you are like a leaning wall, like a tottering fence") — the enemies are the unstable structure that is about to collapse: they attack someone already weakened, and their own violence tilts them toward ruin. A leaning wall and a pushed-over fence are both about to fall — the enemies press against the righteous and lean themselves into collapse.</p>',
    "4": '<p><strong>אַךְ מִשְּׂאֵתוֹ יָעֲצוּ לְהַדִּיחַ</strong> (<em>ʾak misśĕʾētô yāʿăṣû lĕhaddîaḥ</em>, "They only plan to bring him down from his position") — <em>śĕʾēt</em>: dignity, eminence, elevation (the exalted position that the enemies wish to topple). <em>Nādaḥ</em> (hiphil: to push away, to cast down from a height): the plan is demotion from his elevated standing. <strong>יִרְצוּ כָזָב</strong> (<em>yirṣû kāzāb</em>, "they delight in falsehood") — <em>rāṣāh</em>: to take pleasure in, to delight in (the same word as divine pleasure in Ps 44:3 — now the enemies take pleasure in the opposite of divine truth). <strong>בְּפִיו יְבָרֲכוּ וּבְקִרְבָּם יְקַלְלוּ סֶלָה</strong> (<em>bĕpîw yĕbārăkû ûbĕqirbām yĕqallĕlû selāh</em>, "with their mouths they bless, but inwardly they curse") — the double speech: the outer blessing (<em>bārak</em>) concealing the inner curse (<em>qālal</em>). <em>Selāh</em> marks the pause on this hypocrisy.</p>',
    "5": '<p><strong>אַךְ לֵאלֹהִים דּוֹמִּי נַפְשִׁי</strong> (<em>ʾak lêʾlōhîm dômmî napshî</em>, "Be still before God alone, my soul!") — the Psalmist turns to address himself: the imperative <em>dômmî</em> (be still! from <em>dāmam</em>) directed inward. The self-counsel of the Psalter: the Psalmist commands his own soul to the same silence he announced in v1 — now as a directive after the disruption of vv3-4. <strong>כִּי-מִמֶּנּוּ תִּקְוָתִי</strong> (<em>kî-mimmennû tiqwātî</em>, "for my hope comes from him") — <em>tiqwāh</em>: hope, expectation (from <em>qāwāh</em>: to wait with expectation — a cord, a thread stretched taut between the present and the promised future). In v1 it was <em>yĕshûʿāh</em> (salvation) from God; here it is <em>tiqwāh</em> (hope) from God — the inner disposition corresponding to the external salvation.</p>',
    "6": '<p><strong>אַךְ-הוּא צוּרִי וִישׁוּעָתִי מִשְׂגַּבִּי</strong> — the refrain returned, almost identical to v2. The key difference: <strong>לֹא אֶמּוֹט</strong> (<em>lōʾ ʾemmôṭ</em>, "I will not be shaken") — without the qualifier <em>rabbāh</em> ("greatly") of v2. The confidence has deepened through the psalm: in v2 the Psalmist acknowledged possible partial shaking; by v6 the claim is absolute. The psalm\'s movement is from qualified trust (v2: not greatly shaken) to unqualified confidence (v6: not shaken at all). This growth of certainty within the psalm itself models how the act of preaching to one\'s own soul (v5: "Be still, my soul!") produces stronger faith.</p>',
    "7": '<p><strong>עַל-אֱלֹהִים יִשְׁעִי וּכְבוֹדִי</strong> (<em>ʿal-ʾĕlōhîm yishʿî ûkĕbôdî</em>, "In God rests my salvation and my honor") — <em>yeshaʿ</em>: salvation/deliverance; <em>kābôd</em>: honor, weight, glory. Both rest (<em>ʿal</em>: upon) God. <strong>צוּר-עֻזִּי מַחְסִי בֵּאלֹהִים</strong> (<em>ṣûr-ʿuzzî maḥsî bêʾlōhîm</em>, "God is the rock of my strength, my refuge") — <em>ṣûr ʿuzzî</em>: "rock of my strength" — the rock metaphor extended: not just any rock but the source of strength. <em>Maḥseh</em>: the shelter/refuge (as in Ps 46:1). The accumulation of images in this verse: God = salvation, honor, strength-rock, refuge.</p>',
    "8": '<p><strong>בִּטְחוּ בוֹ בְכָל-עֵת עָם</strong> (<em>bitḥû bô bĕkol-ʿêt ʿām</em>, "Trust in him at all times, O people!") — the movement from individual to communal: the Psalmist who preached to his own soul (v5) now preaches the same trust to the whole people (<em>ʿām</em>). <em>Bāṭaḥ</em> (imperative: trust!). <em>Bĕkol-ʿêt</em>: at all times — not only in moments of crisis but continuously. <strong>שִׁפְכוּ-לְפָנָיו לְבַבְכֶם</strong> (<em>shiphkû-lĕpānāyw lĕbabĕkem</em>, "pour out your hearts before him") — <em>shāpak</em>: to pour out (as in Ps 42:4 — the soul poured like water; here the heart poured before God in transparent prayer). <strong>אֱלֹהִים מַחֲסֶה-לָנוּ סֶלָה</strong> (<em>ʾĕlōhîm maḥăseh-lānû selāh</em>, "God is a refuge for us") — the confession extended to "us" — from the individual\'s "my refuge" (v7) to the community\'s "our refuge."</p>',
    "9": '<p><strong>אַךְ הֶבֶל בְּנֵי-אָדָם</strong> (<em>ʾak hebel bĕnê-ʾādām</em>, "Surely common people are only a breath") — <em>bĕnê-ʾādām</em>: sons of Adam/common people (those of ordinary social standing). <em>Hebel</em>: breath, vapor, emptiness (the key word of Ecclesiastes — "vanity of vanities"). <strong>כָּזָב בְּנֵי-אִישׁ</strong> (<em>kāzāb bĕnê-ʾîsh</em>, "people of rank are a deception") — <em>bĕnê-ʾîsh</em>: "sons of man" (the men of distinction — <em>ʾîsh</em> as the person of standing). The low-status and the high-status are both weighed and found empty. <strong>בְּמֹאזְנַיִם לַעֲלוֹת</strong> (<em>bĕmōʾznayim laʿălôt</em>, "weighed in the scales they rise") — the scales of divine justice: placed in the balance, both categories of humanity literally rise (because they are lighter than <em>hebel</em>). The image of the balance going up when a weight is too light — the two classes of humanity together lighter than vapor.</p>',
    "10": '<p><strong>אַל-תִּבְטְחוּ בְעֹשֶׁק</strong> (<em>ʾal-tibṭĕḥû bĕʿōsheq</em>, "Do not trust in extortion") — <em>ʿōsheq</em>: extortion, oppression, gain through wrongful squeezing of others. <strong>וּבְגָזֵל אַל-תֶּהְבָּלוּ</strong> (<em>ûbĕgāzêl ʾal-tehbālû</em>, "do not take false pride in robbery") — <em>gāzal</em>: robbery, seizure (forcible taking); <em>hābal</em>: to become empty, to be vain. <strong>חַיִל כִּי-יָנוּב אַל-תָּשִׂיתוּ לֵב</strong> (<em>ḥayil kî-yānûb ʾal-tāśîtû lêb</em>, "if wealth increases, do not set your heart on it") — <em>ḥayil</em>: wealth, strength (riches as power); <em>nûb</em>: to sprout, to increase (the organic growth of wealth). The warning: the growing of wealth creates a corresponding temptation to trust it. "Do not set your heart on it" — <em>lêb</em> (heart): the center of devotion and loyalty.</p>',
    "11": '<p><strong>אַחַת דִּבֶּר אֱלֹהִים שְׁתַּיִם-זוּ שָׁמַעְתִּי</strong> (<em>ʾaḥat dibbêr ʾĕlōhîm shĕttayim-zû shāmaʿtî</em>, "One thing God has spoken; two things I have heard") — the numerical-saying structure (<em>n/n+1</em>): the same wisdom-speech pattern of Prov 6:16 ("There are six things the LORD hates, seven..."); Amos 1:3 ("For three transgressions... and for four"); Job 33:14. God speaks once; the attentive listener hears the fullness — "two things." The one divine speech contains more than one truth for the receptive ear. <strong>כִּי עֹז לֵאלֹהִים</strong> (<em>kî ʿōz lêʾlōhîm</em>, "that power belongs to God") — the first truth: <em>ʿōz</em> (strength, power) as God\'s exclusive possession (as in Ps 29:1; 46:1). Power is not distributed; it belongs to God alone.</p>',
    "12": '<p><strong>וּלְךָ-אֲדֹנָי חָסֶד</strong> (<em>ûlĕkā-ʾădōnāy ḥāsed</em>, "And to you, O Lord, belongs steadfast love") — the second truth heard from the one divine speech: <em>ḥesed</em> as the companion of <em>ʿōz</em>. Power (<em>ʿōz</em>) and covenant-loyalty (<em>ḥesed</em>) — the divine character is not power alone (which could be terrifying) but power in the service of covenant love. <strong>כִּי-אַתָּה תְשַׁלֵּם לְאִישׁ כְּמַעֲשֵׂהוּ</strong> (<em>kî-ʾattāh tĕshallêm lĕʾîsh kĕmaʿăśêhû</em>, "for you repay each person according to their deeds") — <em>shālam</em> (piel: to repay, to pay in full — the wholeness-root used for moral accountability). The divine repayment is the exercise of both attributes together: power ensures the repayment can be made; <em>ḥesed</em> ensures it is executed in faithfulness rather than arbitrary caprice. Paul cites this verse\'s principle in Rom 2:6.</p>',
  },
  "63": {
    "1": '<p>The superscription places Psalm 63 "when he was in the wilderness of Judah" — likely the Absalom rebellion when David fled Jerusalem into the wilderness (2 Sam 15-16). <strong>אֱלֹהִים אֵלִי אַתָּה</strong> (<em>ʾĕlōhîm ʾêlî ʾattāh</em>, "O God, you are my God") — the possessive: not merely "God" but "my God" — the covenant-claiming of the divine name. <strong>אֲשַׁחֲרֶךָּ</strong> (<em>ʾăshaḥărĕkā</em>, "earnestly I seek you") — <em>shāḥar</em>: to seek at dawn, to search earnestly (the root of <em>shaḥar</em>, the dawn — the early-rising seeker who hunts for God as the dawn hunter hunts for prey). <strong>צָמְאָה לְךָ נַפְשִׁי</strong> (<em>ṣāmĕʾāh lĕkā napshî</em>, "my soul thirsts for you") — <em>ṣāmēʾ</em>: to thirst (as in Ps 42:2). <strong>כָּמַהּ לְךָ בְשָׂרִי</strong> (<em>kāmah lĕkā bĕśārî</em>, "my flesh longs for you") — <em>kāmah</em>: a hapax legomenon (appears only here) — to yearn intensely, to long with physical desire. Both <em>nāpesh</em> (the inner self) and <em>bāśār</em> (flesh/body) are thirsting and yearning — the whole person in physical extremity reaching for God.</p>',
    "2": '<p><strong>כֵּן בַּקֹּדֶשׁ חֲזִיתִיךָ</strong> (<em>kên baqqōdesh ḥăzîtîkā</em>, "So I have gazed upon you in the sanctuary") — <em>ḥāzāh</em>: to gaze, to behold (the prophetic vision-verb — the seer\'s seeing). The paradox: in the wilderness without water (v1), the Psalmist remembers the sanctuary vision — the past temple experience sustains the present wilderness. <strong>לִרְאוֹת עֻזְּךָ וּכְבוֹדֶךָ</strong> (<em>lirʾôt ʿuzzĕkā ûkĕbôdekā</em>, "beholding your power and your glory") — <em>ʿōz</em> and <em>kābôd</em>: the two paired divine attributes seen in the sanctuary — power and weightiness/glory. The sanctuary is where God\'s power and glory are manifested visibly; the wilderness is where the memory of that vision sustains.</p>',
    "3": '<p><strong>כִּי-טוֹב חַסְדְּךָ מֵחַיִּים</strong> (<em>kî-ṭôb ḥasdĕkā mêḥayyîm</em>, "Because your steadfast love is better than life itself") — the theological claim at the heart of the psalm and one of the most radical statements in the Psalter: <em>ḥesed</em> (covenant-loyalty) is better than (<em>ṭôb min</em>) life (<em>ḥayyîm</em>). Life (<em>ḥayyîm</em>) is the highest human good — the thing that sustains everything else. But divine <em>ḥesed</em> exceeds even life in value. Paul makes the same comparison in Phil 1:21 ("to live is Christ, to die is gain") and Phil 1:23 ("to depart and be with Christ is far better"). <strong>שְׂפָתַי יְשַׁבְּחוּנְךָ</strong> (<em>śĕpātay yĕshabbĕḥûnĕkā</em>, "my lips will praise you") — the response to such <em>ḥesed</em>: the lips that would be silent in death are impelled to praise.</p>',
    "4": '<p><strong>כֵּן אֲבָרֶכְךָ בְחַיָּי</strong> (<em>kên ʾăbārekĕkā bĕḥayyāy</em>, "So I will bless you as long as I live") — the pledge of lifelong praise (<em>bĕḥayyāy</em>: in my life — for all its duration). <strong>בְּשִׁמְךָ אֶשָּׂא כַפָּי</strong> (<em>bĕshimkā ʾeśśāʾ kappāy</em>, "in your name I will lift up my hands") — <em>nāśāʾ kappayim</em>: to lift the palms upward (the posture of prayer and supplication — openness to receive, surrender, appeal). The name (<em>shêm</em>) invoked in the gesture: the hands raised to the Name.</p>',
    "5": '<p><strong>כְּמוֹ חֵלֶב וָדֶשֶׁן תִּשְׂבַּע נַפְשִׁי</strong> (<em>kĕmô ḥêleb wādeshen tiśbaʿ napshî</em>, "My soul is satisfied as with the richest of food") — <em>ḥêleb</em>: fat (the richest portion of the sacrificial animal — the fat offered to God in Lev 3:16; 7:23; the fat as the best, richest part); <em>deshen</em>: fatness, marrow, abundance. Together they describe the richest possible feast. The <em>nāpesh</em> satisfied as if gorged on the feast of God\'s presence. <strong>וְשִׂפְתֵי רְנָנוֹת יְהַלֶּל-פִּי</strong> (<em>wĕśiptê rĕnānôt yĕhallel-pî</em>, "my mouth praises you with joyful lips") — <em>rĕnānāh</em>: the ringing joyful cry (as in Ps 61:1 — the urgent ringing cry). The desert-starved lips that longed for God (v1) are now the lips of feasting satisfaction.</p>',
    "6": '<p><strong>אִם-זְכַרְתִּיךָ עַל-יְצוּעָי</strong> (<em>ʾim-zĕkartîkā ʿal-yĕṣûʿāy</em>, "When I remember you on my bed") — <em>zākar</em>: to remember (the covenant remembering of God — keeping the divine character and deeds present in consciousness). <em>Yĕṣûaʿ</em>: a bed, a couch (the reclining place — the night rest). <strong>בְּאַשְׁמֻרוֹת אֶהְגֶּה-בָּךְ</strong> (<em>bĕʾashmurôt ʾehgeh-bāk</em>, "I meditate on you through the watches of the night") — <em>ʾashmurāh</em>: a watch (the night was divided into three watches: evening, midnight, and the morning watch — Exod 14:24; Judg 7:19). <em>Hāgāh</em>: to murmur, to meditate (as in Ps 1:2 — the Torah-meditator murmuring day and night; here the Psalmist meditates on God himself through all the night watches).</p>',
    "7": '<p><strong>כִּי-הָיִיתָ עֶזְרָתָה לִּי</strong> (<em>kî-hāyîtā ʿezrātāh llî</em>, "For you have been my help") — <em>ʿezrāh</em>: help (the <em>ʿezer</em> of Gen 2:18 — the essential help that prevents incompleteness). The past help grounds the present trust. <strong>וּבְצֵל כְּנָפֶיךָ אֲרַנֵּן</strong> (<em>ûbĕṣêl kĕnāpêkā ʾărannên</em>, "and in the shadow of your wings I will rejoice") — the "shadow of your wings" (as in Ps 57:1; 61:4): the wings of the cherubim over the ark, the brooding divine bird. <em>Rānan</em>: to shout for joy (in the midst of the wilderness, the Psalmist shouts with joy because of the remembered and promised divine protection).</p>',
    "8": '<p><strong>דָּבְקָה נַפְשִׁי אַחֲרֶיךָ</strong> (<em>dābĕqāh napshî ʾaḥărêkā</em>, "My soul clings close after you") — <em>dābaq</em>: to cling, to stick fast, to cleave (the marriage-covenant verb of Gen 2:24: "a man shall leave his father and mother and <em>dābaq</em> to his wife"; and Ruth 1:14: Ruth "clung" to Naomi after Orpah departed). The covenant-cleaving that is the deepest expression of love and commitment — the Psalmist\'s <em>nāpesh</em> clinging to God with the totality of the marriage covenant. <strong>בִּי הֶחֱזִיקָה יְמִינֶךָ</strong> (<em>bî heḥĕzîqāh yĕmînekā</em>, "your right hand holds me fast") — <em>ḥāzaq</em> (hiphil: to hold firmly, to grip): God\'s right hand (<em>yāmîn</em>) maintaining the grip on the one who clings. The covenant is mutual: the Psalmist clings to God, and God holds the Psalmist. Neither releases the other.</p>',
    "9": '<p><strong>וְהֵמָּה לְשׁוֹאָה יְבַקְשׁוּ נַפְשִׁי</strong> (<em>wĕhêmmāh lĕshôʾāh yĕbaqshû napshî</em>, "But those who seek to destroy my life") — <em>shôʾāh</em>: devastation, destruction (a word for total ruin — storm and desolation); <em>bāqash</em>: to seek (as in Ps 27:4 — but here in the hostile sense: to hunt). <strong>יָבֹאוּ בְּתַחְתִּיּוֹת הָאָרֶץ</strong> (<em>yābōʾû bĕtaḥtiyyôt hāʾāreṣ</em>, "shall descend into the depths of the earth") — <em>taḥtiyyôt hāʾāreṣ</em>: the lower parts of the earth (the underworld, Sheol — as in Ps 86:13: "you have delivered my soul from the depth of Sheol"; Ezek 26:20). The reversal: those who seek the Psalmist\'s destruction descend to the place they sought to send him.</p>',
    "10": '<p><strong>יַגִּירֻהוּ עַל-יְדֵי-חָרֶב</strong> (<em>yaggîruhû ʿal-yĕdê-ḥāreb</em>, "They will be delivered over to the sword") — <em>gārar</em> (hiphil: to drag, to hand over — the enemies delivered into the power of the sword). <strong>מְנָת שֻׁעָלִים יִהְיוּ</strong> (<em>mĕnāt shûʿālîm yihyû</em>, "they will become prey for jackals") — <em>mĕnāh</em>: a portion, an allotted share; <em>shûʿālîm</em>: jackals (the scavengers of the battlefield and the wilderness). The enemies become the jackals\' food portion — the carrion-eaters taking their allotted share of the fallen. The irony: those who sought to destroy the Psalmist\'s <em>nāpesh</em> (v9) become the animals\' food portion (<em>mĕnāh</em>).</p>',
    "11": '<p><strong>וְהַמֶּלֶךְ יִשְׂמַח בֵּאלֹהִים</strong> (<em>wĕhammelek yiśmaḥ bêʾlōhîm</em>, "But the king will rejoice in God") — the psalm\'s closing affirmation: the king (David, the Psalmist-king) rejoices in God. <strong>כָּל-הַנִּשְׁבָּע בּוֹ יִתְהַלֵּל</strong> (<em>kol-hannishbāʿ bô yithalêl</em>, "all who swear by him will boast in him") — <em>nishbāʿ bô</em>: "swear by him" — to take an oath in the name of the LORD is to invoke him as the witness and guarantor of truth (Gen 21:23; 1 Sam 20:42). Those who swear by the LORD identify themselves with him and find their boast in him alone. <strong>כִּי יִסָּכֵר פִּי דוֹבְרֵי-שָׁקֶר</strong> (<em>kî yissākêr pî dôbĕrê-shāqer</em>, "for the mouths of liars will be silenced") — <em>sākar</em> (niphal: to be stopped, to be plugged — as a stream is blocked): the lying mouths silenced as justice restores truthful speech to the public square.</p>',
  },
  "64": {
    "1": '<p><strong>שְׁמַע-אֱלֹהִים קוֹלִי בְשִׂיחִי</strong> (<em>shĕmaʿ-ʾĕlōhîm qôlî bĕśîḥî</em>, "Hear my voice, O God, in my complaint") — <em>śîaḥ</em>: the meditative complaint, the troubled musing that has become vocal (as in Ps 55:2 — the same word for the unsettled inward meditation voiced as complaint). <strong>מִפַּחַד אוֹיֵב תִּצֹּר חַיָּי</strong> (<em>mippaḥad ʾôyêb tiṣṣōr ḥayyāy</em>, "guard my life from the terror of the enemy") — <em>paḥad</em>: dread, terror (the freezing fear); <em>nāṣar</em>: to guard, to watch over, to keep (the sentinel\'s task applied to the Psalmist\'s life).</p>',
    "2": '<p><strong>תַּסְתִּירֵנִי מִסּוֹד מְרֵעִים</strong> (<em>tastirênî missôd mĕrêʿîm</em>, "shelter me from the conspiracy of the wicked") — <em>sâtar</em> (hiphil: to hide, to shelter); <em>sôd</em>: the secret counsel, the intimate assembly (as in Ps 55:14 — the sweet counsel shared with the companion; here the same word for a malicious conspiracy). <strong>מֵרִגְשַׁת פֹּעֲלֵי אָוֶן</strong> (<em>mêrigshat pōʿălê ʾāwen</em>, "from the scheming mob of evildoers") — <em>rigshah</em>: a tumultuous crowd, a riotous gathering (the noisy assemblage of the evildoers). <em>Pōʿălê ʾāwen</em>: "workers of trouble" (the standard formula from Pss 5:5; 6:8 — those whose craft is harm).</p>',
    "3": '<p><strong>אֲשֶׁר שָׁנְנוּ כַחֶרֶב לְשׁוֹנָם</strong> (<em>ʾăsher shānĕnû kaḥereb lĕshônām</em>, "they sharpen their tongues like swords") — <em>shānan</em>: to whet, to sharpen (to put an edge on a blade — Ps 7:12: God whets his sword; Deut 32:41: the divine sharp sword). The tongue as the blade being deliberately honed for maximum cutting. <strong>דָּרְכוּ חִצָּם דָּבָר מָר</strong> (<em>dārĕkû ḥiṣṣām dābār mār</em>, "and aim bitter words like arrows from a bow") — <em>dārak</em>: to tread, to draw (a bow — as in Ps 7:12). <em>Dābār mār</em>: "bitter words" — the arrows are poisoned with bitterness (<em>mar</em>: bitter, as the Exodus waters of Marah, Exod 15:23).</p>',
    "4": '<p><strong>לִירוֹת בַּמִּסְתָּרִים תָּם</strong> (<em>lîrôt bammistārîm tām</em>, "shooting from hiding places at the innocent") — <em>yārāh</em>: to shoot (the arrow-shooting verb); <em>mistārîm</em>: hiding places, ambush positions; <em>tām</em>: the innocent/blameless one (from <em>tāmam</em>: to be complete, whole — the same root as <em>tāmîm</em>). <strong>פִּתְאֹם יֹרֻהוּ וְלֹא יִירָאוּ</strong> (<em>pitʾōm yōruhû wĕlōʾ yîrāʾû</em>, "they strike suddenly and without fear") — <em>pitʾōm</em>: suddenly, without warning. The ambush of the righteous by the wicked who fear nothing — the combination of cunning strategy and moral recklessness.</p>',
    "5": '<p><strong>יְחַזְּקוּ-לָמוֹ דָּבָר רָע</strong> (<em>yĕḥazzĕqû-lāmô dābār rāʿ</em>, "they scheme their evil plan together") — <em>ḥāzaq</em> (piel: to strengthen, to reinforce — they strengthen the evil word among themselves): the mutual hardening of resolve in wickedness. <strong>יְסַפְּרוּ לִטְמוֹן מוֹקְשִׁים</strong> (<em>yĕsappĕrû liṭmôn môqĕshîm</em>, "they talk of setting traps in secret") — <em>sāpar</em>: to count, to plan (as in Ps 22:17 — they "tell" their plans); <em>ṭāman</em>: to hide, to bury (burying the trap under the surface); <em>môqêsh</em>: a snare, a trap (the same word as the "snare" of Ps 69:22). <strong>אָמְרוּ מִי יִרְאֶה-לָּמוֹ</strong> (<em>ʾāmĕrû mî yirʾeh-llāmô</em>, "they say, \'Who will see us?\'") — the assumption of divine inattention: the conspiracy conducted under the delusion that God is absent or blind.</p>',
    "6": '<p><strong>יַחְפְּשׂוּ-עוֹלֹת תַּמְנוּ חֵפֶשׂ מְחֻפָּשׂ</strong> (<em>yaḥpĕśû-ʿawlōt tamnû ḥêpeś mĕḥuppāsh</em>, "They plan iniquities: \'We have devised a perfect scheme!\'") — <em>ḥāpaś</em>: to search, to devise carefully (to inspect for thoroughness — they have searched out every angle of their plan). <em>Ḥêpeś mĕḥuppāsh</em>: "a searched/exhaustive plan" — the enemies believe their conspiracy to be airtight, undetectable. <strong>וְקֶרֶב אִישׁ וְלֵב עָמֹק</strong> (<em>wĕqereb ʾîsh wĕlêb ʿāmōq</em>, "but the inward thought and heart of a person are unfathomable") — <em>qereb</em>: the inward part; <em>lêb ʿāmōq</em>: a deep/unfathomable heart. The human heart is deeper than any scheme — even the schemers cannot fully know themselves, which means their "perfect plan" is built on a foundation of their own unfathomable depths. God alone can search the deep heart (Jer 17:9-10).</p>',
    "7": '<p><strong>וַיֹּרֵם אֱלֹהִים חֵץ פִּתְאוֹם</strong> (<em>wayyōrêm ʾĕlōhîm ḥêṣ pitʾôm</em>, "But God will shoot his arrow at them; suddenly they will be struck down") — the double ironic reversal: the enemies shot arrows at the blameless (v4); now God shoots his arrow at them. The verb <em>yārāh</em> (to shoot — v4: the enemies shooting; v7: God shooting) binds the reversal together. <em>Pitʾôm</em>: suddenly (as the enemies struck suddenly in v4; now they are struck suddenly). The divine counter-ambush.</p>',
    "8": '<p><strong>וַיַּכְשִׁילוּהוּ עָלֵימוֹ לְשׁוֹנָם</strong> (<em>wayyaksîlûhû ʿălêmô lĕshônām</em>, "God makes their own tongues their undoing") — <em>kāshal</em> (hiphil: to make stumble, to cause to fail — God causing them to stumble): God makes their own weapon (the tongue, v3) trip them into ruin. The irony is perfect: the weapon that attacked the blameless (the sharpened tongue-sword of v3) becomes the instrument of the conspirators\' own destruction. <strong>יִתְנוֹדֲדוּ כָּל-רֹאֵה בָם</strong> (<em>yitnôdădû kol-rōʾeh bām</em>, "all who see them shake their heads and flee") — <em>nûd</em>: to wag, to shake the head (the gesture of astonishment/contempt — as in Ps 44:14; Lam 2:15); <em>bāraḥ</em>: to flee. The onlookers recoil from the sight of the divine judgment.</p>',
    "9": '<p><strong>וַיִּירְאוּ כָּל-אָדָם</strong> (<em>wayyîrĕʾû kol-ʾādām</em>, "Then all people will stand in fear") — the universal reversal: from the conspirators\' boast "who will see us?" (v5) to "all people" standing in fear. <em>Yārēʾ</em>: to fear (the holy fear that precedes worship). <strong>וַיַּגִּידוּ פֹּעַל אֱלֹהִים</strong> (<em>wayyaggîdû poʿal ʾĕlōhîm</em>, "they will proclaim what God has done") — <em>nāgad</em> (hiphil: to declare, to proclaim): the reversal produces proclamation — what the wicked kept secret (their plans) now becomes the public declaration of God\'s work. <strong>וּמַעֲשֵׂהוּ הִשְׂכִּילוּ</strong> (<em>ûmaʿăśêhû hiśkîlû</em>, "and ponder his deeds") — <em>śākal</em> (hiphil: to understand, to ponder wisely): not just announcement but theological comprehension — the community understands what God\'s counter-arrow means.</p>',
    "10": '<p><strong>יִשְׂמַח צַדִּיק בַּיהוָה</strong> (<em>yiśmaḥ ṣaddîq baYHWH</em>, "The righteous will rejoice in the LORD") — the righteous person\'s joy is not in vindication or revenge but in the LORD himself. <strong>וְחָסָה בוֹ</strong> (<em>wĕḥāsāh bô</em>, "and take refuge in him") — <em>ḥāsāh</em>: to flee for refuge (the fundamental trust-verb of the Psalter — as in Ps 2:12; 5:11). <strong>וְיִתְהַלְלוּ כָּל-יִשְׁרֵי-לֵב</strong> (<em>wĕyithalĕlû kol-yishrê-lêb</em>, "all the upright in heart shall boast") — <em>yāshar lêb</em>: "upright in heart" — the straight/level-hearted, whose inner orientation matches the divine standard of righteousness. Their boast (<em>hālal</em>) is not self-boasting but the boasting in God of those who have nowhere else to boast.</p>',
  },
  "65": {
    "1": '<p>Psalm 65 is a hymn for the harvest — one of the great nature-and-worship psalms. <strong>לְךָ דֻמִיָּה תְהִלָּה</strong> (<em>lĕkā dûmiyyāh tĕhillāh</em>, "Praise awaits you in silence, O God, in Zion") — <em>dûmiyyāh</em>: silence (as in Ps 62:1 — the expectant, laden silence). <em>Tĕhillāh</em>: praise (the root of Psalms — <em>tĕhillîm</em>). The phrase is paradoxical: "silence is praise" — the deepest worship is the awed silence before the divine presence that transcends words. The Talmudic interpretation (b. Megillah 18a): "silence is the best medicine for prayer" — the highest praise before Zion\'s God is the silence of awe. <strong>וְלְךָ יְשֻׁלַּם-נֶדֶר</strong> (<em>wĕlĕkā yĕshullam-neder</em>, "and to you the vow shall be fulfilled") — <em>shālam</em> (pual: to be completed, fulfilled): the vow is paid in full at Zion.</p>',
    "2": '<p><strong>שֹׁמֵעַ תְּפִלָּה</strong> (<em>shōmêaʿ tĕpillāh</em>, "O you who hear prayer") — the divine epithet: the one whose defining characteristic is that he hears prayer. <strong>עָדֶיךָ כָּל-בָּשָׂר יָבֹאוּ</strong> (<em>ʿādêkā kol-bāśār yābōʾû</em>, "to you all flesh shall come") — <em>kol-bāśār</em>: all flesh — the universal scope (as in Joel 2:28/Acts 2:17: "I will pour out my Spirit on all flesh"). The prayer-hearing God draws all flesh — the entire mortal world — toward himself. The harvest psalm is also the universal-access psalm: the God who provides grain for all the earth also receives all the earth\'s prayer.</p>',
    "3": '<p><strong>דִּבְרֵי עֲוֹנֹת גָּבְרוּ עָלַי</strong> (<em>dibrê ʿăwōnōt gābĕrû ʿālay</em>, "When our sins overwhelm us") — <em>ʿāwōn</em>: iniquity, perversity; <em>gābar</em> (qal: to be strong, to overpower): the sins become stronger than the Psalmist — they overwhelm and overcome. <strong>פְשָׁעֵינוּ אַתָּה תְכַפְּרֵם</strong> (<em>pĕshāʿênû ʾattāh tĕkappĕrêm</em>, "you atone for our transgressions") — <em>peshaʿ</em>: rebellious transgression (willful defiance — as in Ps 32:1); <em>kāpar</em> (piel: to atone, to cover, to wipe clean — the verb of the Day of Atonement/<em>Yôm hakkippûrîm</em>). The atonement is entirely God\'s action: "you atone" — not "we atone." The divine covering of what the human cannot remove.</p>',
    "4": '<p><strong>אַשְׁרֵי תִּבְחַר וּתְקָרֵב</strong> (<em>ʾashrê tiḇḥar ûtĕqārêb</em>, "Blessed is the one you choose and bring near") — the divine election (<em>bāḥar</em>: to choose — Deut 7:6; Isa 41:8-9) paired with access (<em>qārab</em>: to bring near — the priestly drawing-near of Lev 10:3). Election and access are both divine initiatives: God chooses and God draws near. <strong>יִשְׁכֹּן חֲצֵרֶיךָ</strong> (<em>yishkōn ḥăṣêrêkā</em>, "to dwell in your courts") — <em>shākan</em>: to dwell (the <em>Mishkān</em>/<em>Shekinah</em> root — the dwelling in God\'s courts as the experience of his dwelling-presence). <strong>נִשְׂבְּעָה בְּטוּב בֵּיתֶךָ</strong> (<em>niśbĕʿāh bĕṭûb bêtekā</em>, "we shall be satisfied with the goodness of your house") — <em>śābaʿ</em>: to be satisfied, to be full (as in Ps 63:5 — the fat-and-marrow satisfaction). The goodness (<em>ṭûb</em>) of the divine house — all the goodness concentrated in the dwelling-place of God.</p>',
    "5": '<p><strong>נוֹרָאוֹת בְּצֶדֶק תַּעֲנֵנוּ</strong> (<em>nôrāʾôt bĕṣedeq taʿănênû</em>, "By awesome deeds in righteousness you answer us") — <em>nôrāʾôt</em>: awesome acts (things that inspire holy fear — from <em>yārēʾ</em>: to fear); <em>ṣedeq</em>: righteousness (the acts are awesome and righteous simultaneously). <strong>אֱלֹהֵי יִשְׁעֵנוּ</strong> (<em>ʾĕlōhê yishʿênû</em>, "O God of our salvation") — the God whose defining character is salvation. <strong>מִבְטָח כָּל-קַצְוֵי-אֶרֶץ וְיָם רְחֹקִים</strong> (<em>mibṭaḥ kol-qaṣwê-ʾereṣ wĕyām rĕḥōqîm</em>, "you are the hope of all the ends of the earth and of the most distant seas") — <em>mibṭāḥ</em>: the ground of trust, the hope (from <em>bāṭaḥ</em>). The scope is universal: the ends of the earth and the farthest seas — the entire inhabited world has its ground of hope in this one God.</p>',
    "6": '<p><strong>מֵכִין הָרִים בְּכֹחוֹ</strong> (<em>mêkîn hārîm bĕkōḥô</em>, "the one who by his strength sets the mountains in place") — <em>kûn</em> (hiphil: to establish, to set firm): the divine Creator-Establisher who fixed the mountains in their positions. <em>Kōaḥ</em>: strength, might (not the relational <em>ḥesed</em> but the raw power of creation). <strong>נֶאְזָר בִּגְבוּרָה</strong> (<em>neʾzār bigĕbûrāh</em>, "who is clothed with power") — <em>ʾāzar</em> (niphal: to be girded, to wear as a belt): power (<em>gĕbûrāh</em>) as the divine garment. The creator-God wearing strength as a warrior wears his belt — power not acquired but constitutive.</p>',
    "7": '<p><strong>מַשְׁבִּיחַ שְׁאוֹן יַמִּים</strong> (<em>mashbîaḥ shĕʾôn yammîm</em>, "you still the roaring of the seas") — <em>shābat</em> (hiphil: to cause to cease — the Sabbath-rest root): God making the sea\'s roar cease (as in Ps 46:9 — "he makes wars cease"). <em>Shĕʾôn yammîm</em>: the roar of the seas — the same cosmic chaos-force. <strong>שְׁאוֹן גַּלֵּיהֶם</strong> (<em>shĕʾôn gallêhem</em>, "the roaring of their waves") — the waves\' tumult. <strong>וַהֲמוֹן לְאֻמִּים</strong> (<em>wahămôn lĕʾummîm</em>, "and the uproar of the nations") — the same verb (<em>shābat</em>) applied to the political world: the divine stilling of the sea\'s chaos and the nations\' tumult are parallel acts of the same creative governance.</p>',
    "8": '<p><strong>וַיִּירְאוּ יֹשְׁבֵי קְצָווֹת</strong> (<em>wayyîrĕʾû yōshĕbê qĕṣāwôt</em>, "Those who live at earth\'s farthest bounds stand in awe of your signs") — <em>qĕṣāwôt</em>: the ends/limits (as in Isa 41:9: "I took you from the ends of the earth"). The furthest peoples stand in awe (<em>yārēʾ</em>). <strong>מוֹצָאֵי-בֹקֶר וָעֶרֶב תַּרְנִין</strong> (<em>môṣāʾê-bōqer wāʿereb tarnîn</em>, "you make the sunrise and the sunset ring with joy") — <em>môṣāʾê bōqer</em>: "the exits/departures of morning" — the sunrise; <em>ʿereb</em>: evening. <em>Rānan</em> (hiphil: to cause to sing/ring with joy): God making the sunrise and sunset themselves ring with joyful song — the entire daily cycle is a divine shout of joy. Creation\'s own praise.</p>',
    "9": '<p><strong>פָּקַדְתָּ הָאָרֶץ וַתְּשֹׁקְקֶהָ</strong> (<em>pāqadtā hāʾāreṣ wattĕshōqĕqehā</em>, "You visit the earth and water it abundantly") — <em>pāqad</em>: to visit, to attend to (the divine inspection of covenantal care — as God "visited" his people in Exod 3:16; 4:31). <em>Shāqaq</em> (polel: to water abundantly, to drench): the divine farmer soaking his field with water. <strong>רַבַּת תַּעְשְׁרֶנָּה</strong> (<em>rabbat taʿshĕrenāh</em>, "you enrich it greatly") — <em>ʿāshar</em> (piel: to make rich, to enrich): the earth enriched by divine attention. <strong>פֶּלֶג אֱלֹהִים מָלֵא מָיִם</strong> (<em>peleg ʾĕlōhîm mālêʾ māyim</em>, "with the river of God, full of water") — <em>peleg ʾĕlōhîm</em>: "the river of God" — the heavenly water-supply (as in Job 38:25-28: the channels of water that God directs). The rain is the river of God arriving from above.</p>',
    "10": '<p><strong>תְּלָמֶיהָ רַוֵּה נַחֵת גְּדוּדֶיהָ</strong> (<em>tĕlāmêhā rāwwêh naḥêt gĕdûdêhā</em>, "you soak its furrows abundantly, you level its ridges") — <em>rāwāh</em> (piel: to saturate, to drench — as the drenched man is fully soaked): the furrows flooded with water. <em>Nāḥat</em> (hiphil: to bring down, to level): flattening the high ridges between furrows. <strong>בִּרְבִיבִים תְּמֹגְגֶנָּה</strong> (<em>birbîbîm tĕmōgĕgenāh</em>, "you soften it with showers") — <em>rĕbîbîm</em>: abundant showers (the spring rains — Deut 32:2: "let my teaching drop as the rain, my speech distill as the dew, like gentle rain upon tender grass, and like showers upon the herb"). <em>Māwag</em> (polel: to soften, to dissolve): rain making the hard ground soft for planting.</p>',
    "11": '<p><strong>עִטַּרְתָּ שְׁנַת טוֹבָתֶךָ</strong> (<em>ʿiṭṭartā shĕnat ṭôbātekā</em>, "You crown the year with your bounty") — <em>ʿāṭar</em> (piel: to encircle with a crown — to put a crown on): the year itself crowned. <em>Ṭôbāh</em>: goodness, bounty. The entire agricultural year, from spring planting to autumn harvest, is treated as if it were a king receiving a crown of goodness — the year of harvest is God\'s royal gift. <strong>וּמַעְגָּלֶיךָ יִרְעֲפוּן דָּשֶׁן</strong> (<em>ûmaʿgālêkā yirʿăpûn dāshen</em>, "your wagon tracks overflow with abundance") — <em>maʿgāl</em>: a track, a wheel-rut, a path (the tracks of God\'s divine chariot-wagon that has traveled over the earth bringing the harvest). <em>Rāʿap</em>: to drop, to overflow (the wagon-tracks of the divine harvester overflowing with the fat of the harvest). God moving through the earth as a farmer moves through his field.</p>',
    "12": '<p><strong>יִרְעֲפוּ נְאוֹת מִדְבָּר</strong> (<em>yirʿăpû nĕʾôt midbar</em>, "the pastures of the wilderness overflow") — even the <em>midbar</em> (wilderness/steppes — the place without permanent water) receives the overflow: the abundance spills from the cultivated fields into the wild pastures. <strong>וְגִיל גְּבָעוֹת תַּחְגֹּרְנָה</strong> (<em>wĕgîl gĕbāʿôt taḥgōrĕnāh</em>, "the hills are wrapped in rejoicing") — <em>gîl</em>: the dancing-joy (the physical exultation of movement — as in Ps 45:15); <em>ḥāgar</em>: to gird, to wrap around. The hills girdled/clothed with rejoicing — the landscape dressed in celebration. The inanimate hills personified as joyful dancers girding themselves for the harvest-feast.</p>',
    "13": '<p><strong>לָבְשׁוּ כָרִים הַצֹּאן</strong> (<em>lābĕshû kārîm haṣṣōʾn</em>, "the meadows are dressed with flocks") — <em>lābash</em>: to be clothed — the meadows wear the flocks as their garment. <strong>וַעֲמָקִים יַעַטְפוּ-בָר</strong> (<em>waʿămāqîm yaʿaṭpû-bār</em>, "the valleys are blanketed with grain") — <em>ʿāṭap</em>: to cover, to envelop (as a cloak envelops — as in Ps 73:6: pride as a necklace/chain); <em>bār</em>: grain, pure grain (the produce of the threshing floor). <strong>יִתְרוֹעֲעוּ אַף-יָשִׁירוּ</strong> (<em>yitrôʿăʿû ʾap-yāshîrû</em>, "they shout for joy, they break into song!") — the personified landscape in full-throated praise: the shout (<em>rûaʿ</em>: the battle-cry/acclamation of joy) and the song (<em>shîr</em>). The creation itself joins the psalm of praise — the harvest the occasion for universal natural praise that closes the Psalm with "all the earth" joining the worship begun at Zion (v1).</p>',
  },
  "66": {
    "1": '<p>Psalm 66 pivots midway from communal hymn (vv1-12) to personal testimony (vv13-20) — the universal "all the earth" to the individual "I." The opening: <strong>הָרִיעוּ לֵאלֹהִים כָּל-הָאָרֶץ</strong> (<em>hārîʿû lêʾlōhîm kol-hāʾāreṣ</em>, "Shout joyfully to God, all the earth!") — <em>rûaʿ</em> (hiphil: to raise the acclamation-shout — the battle-cry of celebration, the coronation shout): all the earth called to raise the universal shout of divine kingship. The scope: not Israel only but all the earth (<em>kol-hāʾāreṣ</em>).</p>',
    "2": '<p><strong>זַמְּרוּ כְבוֹד-שְׁמוֹ</strong> (<em>zammĕrû kĕbôd-shĕmô</em>, "Sing the glory of his name") — <em>zāmar</em>: to sing with instruments; <em>kĕbôd-shĕmô</em>: "the glory of his name" — the reputation and weight (<em>kābôd</em>) of the divine name proclaimed in song. <strong>שִׂימוּ כָבוֹד תְּהִלָּתוֹ</strong> (<em>śîmû kābôd tĕhillātô</em>, "make his praise resplendent") — <em>śîm kābôd</em>: "put weight/glory on" — making the praise itself glorious. The language of weighting the praise with the full dignity of what God has done.</p>',
    "3": '<p><strong>אִמְרוּ לֵאלֹהִים מַה-נּוֹרָא מַעֲשֶׂיךָ</strong> (<em>ʾimrû lêʾlōhîm māh-nôrāʾ maʿăśêkā</em>, "Say to God, \'How awesome are your deeds!\'") — <em>nôrāʾ</em>: awesome, fear-inducing (the holy fear produced by encountering divine power — as in Ps 65:5). <strong>בְּרֹב עֻזְּךָ יְכַחֲשׁוּ-לְךָ אֹיְבֶיךָ</strong> (<em>bĕrōb ʿuzzĕkā yĕkaḥăshû-lĕkā ʾōyĕbêkā</em>, "through the greatness of your power your enemies cower before you") — <em>kāḥash</em> (piel: to cringe, to deny, to submit falsely): the enemies making a reluctant submission — not willing worship but the forced cringing of the defeated before irresistible power. Even reluctant submission is part of the divine sovereignty.</p>',
    "4": '<p><strong>כָּל-הָאָרֶץ יִשְׁתַּחֲווּ לְךָ</strong> (<em>kol-hāʾāreṣ yishtaḥăwû lĕkā</em>, "All the earth bows down before you") — <em>shāḥāh</em> (hishtaphel: to bow down, to prostrate in worship): the universal prostration of all the earth. <strong>יְזַמְּרוּ-לָךְ יְזַמְּרוּ שְׁמֶךָ</strong> (<em>yĕzammĕrû-lāk yĕzammĕrû shĕmekā</em>, "they sing to you, they sing praises to your name") — the double <em>zāmar</em>: the first directed to "you" (God himself), the second to "your name" (the articulated divine character and reputation). <em>Selāh</em>.</p>',
    "5": '<p><strong>לְכוּ וּרְאוּ מִפְעֲלוֹת אֱלֹהִים</strong> (<em>lĕkû ûrĕʾû mipʿălōt ʾĕlōhîm</em>, "Come and see what God has done") — the invitation to witness (as in Ps 46:8: "Come, behold the works of the LORD"). <em>Pōʿal</em>: works, deeds. <strong>נוֹרָא עֲלִילָה עַל-בְּנֵי אָדָם</strong> (<em>nôrāʾ ʿălîlāh ʿal-bĕnê ʾādām</em>, "he is awesome in his acts toward humanity") — <em>ʿălîlāh</em>: a deed, an act (often a great/mighty act — Isa 12:4; Ps 9:11). The divine deeds done "upon" (<em>ʿal</em>) humanity — performed for human benefit and human witness.</p>',
    "6": '<p><strong>הָפַךְ יָם לְיַבָּשָׁה</strong> (<em>hāpak yām lĕyabbāshāh</em>, "He turned the sea into dry land") — <em>hāpak</em>: to turn, to overturn (the transforming reversal): the Exodus event (Exod 14:21-22 — the sea turned to dry land for the crossing). <strong>בַּנָּהָר יַעַבְרוּ בְרָגֶל</strong> (<em>bannāhār yaʿabrû bĕrāgel</em>, "they crossed the river on foot") — possibly the Jordan crossing under Joshua (Josh 3:14-17) — two great water-crossings on foot cited as definitive acts of divine power. <strong>שָׁם נִשְׂמְחָה-בּוֹ</strong> (<em>shām niśmĕḥāh-bô</em>, "there we rejoiced in him") — the place of crossing is the place of joy: the sea crossed = rejoicing in God. Exodus 15:1-21 is the great rejoicing at the sea.</p>',
    "7": '<p><strong>מֹשֵׁל בִּגְבוּרָתוֹ עוֹלָם</strong> (<em>mōshêl bigĕbûrātô ʿôlām</em>, "He rules by his power forever") — <em>māshal</em>: to rule, to govern (the divine governance of history). <em>Gĕbûrāh</em>: might, heroic strength (as in Ps 65:6). <strong>עֵינָיו בַּגּוֹיִם תִּצְפֶּינָה</strong> (<em>ʿênāyw baggôyim tiṣpêynāh</em>, "his eyes watch over the nations") — <em>ṣāpāh</em>: to watch, to spy out, to look out from a height (the watchtower-verb: God as the elevated watchman observing all the nations). <strong>הַסּוֹרְרִים אַל-יָרוּמוּ לָמוֹ סֶלָה</strong> (<em>hassôrĕrîm ʾal-yārûmû lāmô selāh</em>, "let the rebellious not exalt themselves") — <em>sôrēr</em>: the stubborn rebel (Deut 21:18, 20 — the rebellious son). The rebellious nations under the divine eye cannot ultimately exalt themselves.</p>',
    "8": '<p><strong>בָּרְכוּ עַמִּים אֱלֹהֵינוּ</strong> (<em>bārĕkû ʿammîm ʾĕlōhênû</em>, "Bless our God, O peoples!") — the summons addressed to <em>ʿammîm</em> (peoples — the plural including all nations) to bless "our God" (<em>ʾĕlōhênû</em> — Israel\'s God claimed as the universal God). <strong>וְהַשְׁמִיעוּ קוֹל תְּהִלָּתוֹ</strong> (<em>wĕhashmiʿû qôl tĕhillātô</em>, "let the sound of his praise be heard") — <em>shāmaʿ</em> (hiphil: to cause to be heard): making the praise audible — the sound of praise as the evidence of God\'s reality.</p>',
    "9": '<p><strong>הַשָּׂם נַפְשֵׁנוּ בַּחַיִּים</strong> (<em>hashśām napshênû baḥayyîm</em>, "He keeps our lives in life") — <em>śûm</em> (hiphil participle: the one who places/sets): God as the one who places the <em>nāpesh</em> (life) within life itself — sustaining existence from within. <strong>וְלֹא-נָתַן לַמּוֹט רַגְלֵנוּ</strong> (<em>wĕlōʾ-nātan lammôṭ raglênû</em>, "and does not allow our feet to stumble") — <em>māṭ</em>: to totter (as in Ps 62:2 — the firm foundation that prevents the great shaking). God not allowing the foot to slip: the preserving providence that holds the community upright.</p>',
    "10": '<p><strong>כִּי-בְחַנְתָּנוּ אֱלֹהִים</strong> (<em>kî-bĕḥantānû ʾĕlōhîm</em>, "For you, O God, have tested us") — <em>bāḥan</em>: to test, to examine (the assay of metal — the same root as <em>bōḥan ʾeben</em>, "testing stone" of Isa 28:16). <strong>צְרַפְתָּנוּ כִּצְרָף-כָּסֶף</strong> (<em>ṣĕraptānû kiṣrāp-kesep</em>, "you have refined us as silver is refined") — <em>ṣārap</em>: to refine (to smelt metal and remove impurities — the same refining image as Mal 3:3: "he will sit as a refiner and purifier of silver"). The suffering of vv11-12 is the furnace of refining: painful but producing purer metal. The suffering is not purposeless but productive.</p>',
    "11": '<p><strong>הֲבֵאתָנוּ בַמְּצוּדָה</strong> (<em>hăbêʾtānû bammĕṣûdāh</em>, "you brought us into the net") — <em>mĕṣôdāh</em>: a net, a trap (the mesh that catches and holds — the image of captivity or siege). God himself bringing his people into the net — the enemy\'s captivity as the divine instrument of refining. <strong>שַׂמְתָּ מוּעָקָה בְמָתְנֵינוּ</strong> (<em>śamtā mûʿāqāh bĕmātnênû</em>, "you laid a crushing burden on our backs") — <em>mûʿāqāh</em>: a pressed/crushing burden (hapax — from <em>ʿûq</em>: to press down). The burden that bends the back — the oppression.</p>',
    "12": '<p><strong>הִרְכַּבְתָּ אֱנוֹשׁ לְרֹאשֵׁנוּ</strong> (<em>hirkkabtā ʾĕnôsh lĕrōʾshênû</em>, "you let men ride over our heads") — <em>rākab</em> (hiphil: to cause to ride): the humiliating image of conquerors riding over the prostrate defeated — complete subjugation (Isa 51:23: "I will put it into the hand of your tormentors who said to you, \'Bow down, that we may pass over you\'"). <strong>בָּאנוּ-בָאֵשׁ וּבַמַּיִם</strong> (<em>bāʾnû-bāʾêsh ûbammayim</em>, "we went through fire and through water") — the two elemental trials (Isa 43:2: "When you pass through the waters, I will be with you; and through the rivers, they shall not overwhelm you; when you walk through fire you shall not be burned"). Both extremes: the destroying fire and the drowning water. <strong>וַתּוֹצִיאֵנוּ לָרְוָיָה</strong> (<em>wattôṣîʾênû lārĕwāyāh</em>, "yet you brought us out to a wide and spacious place") — <em>rĕwāyāh</em>: saturation, abundance, the spacious place (from <em>rāwāh</em>: to be saturated — as in Ps 65:10: the drenched field). The reversal: from fire and water to the well-watered wide place of abundance. The silver refined comes out pure.</p>',
    "13": '<p>At v13 the psalm shifts from communal "we" to personal "I" — the individual believer\'s testimony: <strong>אָבוֹא בֵיתְךָ בְעוֹלוֹת</strong> (<em>ʾābôʾ bêtĕkā bĕʿôlôt</em>, "I will come into your house with burnt offerings") — <em>ʿôlāh</em>: the burnt offering (wholly consumed on the altar — the total-surrender offering). The entering the house of God with the sacrifice pledged in crisis. <strong>אֲשַׁלֵּם לְךָ נְדָרָי</strong> (<em>ʾăshallêm lĕkā nĕdāray</em>, "I will fulfill my vows to you") — <em>shālam</em> (piel: to complete, to pay): the vows paid in full (as in Ps 61:8; 65:1). The covenant of crisis vows repaid at the sanctuary.</p>',
    "14": '<p><strong>אֲשֶׁר-פָּצוּ שְׂפָתַי</strong> (<em>ʾăsher-pāṣû śĕpātay</em>, "the vows that my lips uttered") — <em>pāṣāh</em>: to open wide (the lips parting in the urgent promise of crisis). <strong>וְדִבֶּר-פִּי בַּצַּר-לִי</strong> (<em>wĕdibber-pî baṣṣar-lî</em>, "and my mouth spoke in my time of trouble") — <em>ṣar</em>: the tight-place, the distress (as in Ps 18:6 — the narrow place of the enemy\'s pressing). The vow spoken in the tight-place, now to be honored in the wide-place (v12: <em>rĕwāyāh</em>).</p>',
    "15": '<p><strong>עֹלוֹת מֵחִים אַעֲלֶה-לָּךְ</strong> (<em>ʿôlôt mêḥîm ʾaʿăleh-llāk</em>, "I will offer you burnt offerings of fattened animals") — <em>mêḥîm</em>: the fat ones (fully fattened animals — the finest of the flock). <strong>עִם-קְטֹרֶת אֵילִים</strong> (<em>ʿim-qĕṭōret ʾêlîm</em>, "with the rising smoke of rams") — <em>qĕṭōret</em>: incense, fragrant smoke (the ascending smoke of sacrifice as the visual image of prayer rising to God — Ps 141:2; Rev 8:4). <em>Selāh</em> marks the pause before the invitation to witness.</p>',
    "16": '<p><strong>לְכוּ-שִׁמְעוּ וַאֲסַפְּרָה</strong> (<em>lĕkû-shîmʿû waʾăsappĕrāh</em>, "Come and hear, and I will tell") — the personal testimony opened to the community: <em>sāpar</em>: to count, to recount, to narrate (as in Ps 22:30-31 — the future generation will declare/<em>sāpar</em> God\'s deeds). <strong>כָּל-יִרְאֵי אֱלֹהִים</strong> (<em>kol-yirʾê ʾĕlōhîm</em>, "all you who fear God") — the audience: the God-fearing community (<em>yirʾê ʾĕlōhîm</em> — the ones whose inner orientation is holy fear). <strong>אֲשֶׁר עָשָׂה לְנַפְשִׁי</strong> (<em>ʾăsher ʿāśāh lĕnapshî</em>, "what he has done for me") — the personal testimony: the specific deeds done for the individual <em>nāpesh</em>.</p>',
    "17": '<p><strong>אֵלָיו פִּי-קָרָאתִי</strong> (<em>ʾêlāyw pî-qārāʾtî</em>, "I cried out to him with my mouth") — the sequence: crisis cry → divine answer. <strong>וְרוֹמַם תַּחַת לְשׁוֹנִי</strong> (<em>wĕrômam taḥat lĕshônî</em>, "and his praise was on my tongue") — <em>rômam</em>: exaltation (the lifting-up of God in praise — the praise was already forming on the tongue while the cry was being made). The prayer and the praise simultaneous: the mouth cries and the tongue praises.</p>',
    "18": '<p><strong>אָוֶן אִם-רָאִיתִי בְלִבִּי</strong> (<em>ʾāwen ʾim-rāʾîtî bĕlibbî</em>, "If I had cherished sin in my heart") — <em>rāʾāh</em> (qal: to see — here: to look at with approval, to cherish, to regard fondly): not accidentally sinning but deliberately cultivating sin in the heart. <em>ʾĀwen</em>: harmful iniquity (as in Ps 58:2; 64:2 — the trouble/harm that one works). <strong>לֹא יִשְׁמַע אֲדֹנָי</strong> (<em>lōʾ yishmaʿ ʾădōnāy</em>, "the Lord would not have listened") — the prayer-condition: the cherished, hidden sin in the heart renders prayer unheard. John 9:31: "We know that God does not listen to sinners; but if anyone is a worshiper of God and does his will, God listens to him." The condition is not sinless perfection but the non-cherishing of known sin.</p>',
    "19": '<p><strong>אָכֵן שָׁמַע אֱלֹהִים</strong> (<em>ʾākên shāmaʿ ʾĕlōhîm</em>, "But truly God has heard") — <em>ʾākên</em>: truly, surely (the strong affirmation — like <em>ʾak</em> of Ps 62:1). The condition of v18 was NOT met: the Psalmist did not cherish sin, and so God heard. <strong>הִקְשִׁיב בְּקוֹל תְּפִלָּתִי</strong> (<em>hiqshîb bĕqôl tĕpillātî</em>, "he has attended to the voice of my prayer") — <em>qāshab</em> (hiphil: to incline the ear, to pay careful attention): God\'s attentive ear to the prayer\'s voice — not merely acknowledging but listening with care.</p>',
    "20": '<p><strong>בָּרוּךְ אֱלֹהִים</strong> (<em>bārûk ʾĕlōhîm</em>, "Blessed be God!") — the closing benediction: the Psalmist blesses God in return for being heard. <strong>אֲשֶׁר לֹא-הֵסִיר תְּפִלָּתִי וְחַסְדּוֹ מֵאִתִּי</strong> (<em>ʾăsher lōʾ-hêsîr tĕpillātî wĕḥasdô mêʾittî</em>, "who has not turned away my prayer or withheld his steadfast love from me") — the double negative celebration: God did NOT turn away the prayer, and God did NOT withhold his <em>ḥesed</em>. The psalm that began with the universal shout of all the earth (v1) ends with the individual\'s personal testimony that the <em>ḥesed</em> — the covenant-loyalty — reaches even into individual crisis and is not withheld. The universal scope and the intimate personal are united in the one <em>ḥesed</em>.</p>',
  },
  "67": {
    "1": '<p>Psalm 67 is the Aaronic blessing (Num 6:24-26) universalized into a missionary prayer. <strong>אֱלֹהִים יְחָנֵּנוּ וִיבָרְכֵנוּ</strong> (<em>ʾĕlōhîm yĕḥannênû wîbārĕkênû</em>, "May God be gracious to us and bless us") — the two blessings: <em>ḥānan</em> (to show grace, unearned favor) and <em>bārak</em> (to bless). <strong>יָאֵר פָּנָיו אִתָּנוּ סֶלָה</strong> (<em>yāʾêr pānāyw ʾittānû selāh</em>, "and may he cause his face to shine upon us") — <em>ʾôr</em> (hiphil: to cause to shine): the face of God shining as light — the Aaronic priestly blessing in its exact form: Num 6:25 "the LORD make his face shine on you and be gracious to you." The Aaronic blessing becomes the opening petition of the psalm — Israel prays for the blessing as the launching pad for the universal proclamation that follows.</p>',
    "2": '<p><strong>לָדַעַת בָּאָרֶץ דַּרְכֶּךָ</strong> (<em>lādaʿat bāʾāreṣ darkekā</em>, "so that your way may be known on earth") — the purpose of Israel\'s blessing: not Israel\'s private enrichment but the earth\'s knowledge (<em>dāʿat</em>) of God\'s <em>derek</em> (way — manner of acting, characteristic path). The blessing is the instrument of proclamation: Israel blessed → earth knows God\'s way. <strong>בְּכָל-גּוֹיִם יְשׁוּעָתֶךָ</strong> (<em>bĕkol-gôyim yĕshûʿātekā</em>, "your saving power among all the nations") — <em>yĕshûʿāh</em>: salvation; <em>kol-gôyim</em>: all the nations. The salvation made known in Israel is the salvation destined for all nations — the Abrahamic logic: "through you all the families of the earth will be blessed" (Gen 12:3). Paul quotes this in Gal 3:8 as the "gospel preached to Abraham."</p>',
    "3": '<p><strong>יוֹדוּךָ עַמִּים אֱלֹהִים</strong> (<em>yôdûkā ʿammîm ʾĕlōhîm</em>, "Let the peoples praise you, O God!") — the refrain (repeated identically in v5): <em>yādāh</em>: to praise, to give thanks (to raise the hand in acknowledgment — the same root as <em>tôdāh</em>/thanksgiving). <strong>יוֹדוּךָ עַמִּים כֻּלָּם</strong> (<em>yôdûkā ʿammîm kullām</em>, "let all the peoples give you praise!") — the intensification: not just "peoples" but "all the peoples" (<em>kullām</em>: the totality). The refrain brackets the central vision of vv4-6 on both sides, creating a triptych: universal praise (v3) → reasons (vv4-6) → universal praise (v5).</p>',
    "4": '<p><strong>יִשְׂמְחוּ וִירַנְּנוּ לְאֻמִּים</strong> (<em>yiśmĕḥû wîrannĕnû lĕʾummîm</em>, "Let the nations be glad and shout for joy!") — <em>śāmaḥ</em>: to rejoice; <em>rānan</em>: to shout with joy (the ringing jubilant cry). <strong>כִּי-תִשְׁפֹּט עַמִּים מִישֹׁר</strong> (<em>kî-tishpōṭ ʿammîm mîshōr</em>, "for you will judge the peoples with fairness") — <em>mîshōr</em>: the level/straight (from <em>yāshar</em>: straight) — impartial, equitable judgment. The nations can rejoice in God\'s universal governance because his judgment is straight/fair — not partial toward Israel. <strong>וּלְאֻמִּים בָּאָרֶץ תַּנְחֵם סֶלָה</strong> (<em>ûlĕʾummîm bāʾāreṣ tanḥêm selāh</em>, "and guide the nations of the earth") — <em>nāḥāh</em>: to guide, to lead (the shepherd-guide verb of Ps 23:3; 31:3; 43:3). God guiding all the nations — not just Israel but the entire family of nations. <em>Selāh</em> marks the pause on this vision of universal divine governance.</p>',
    "5": '<p>The refrain repeated from v3: <strong>יוֹדוּךָ עַמִּים אֱלֹהִים יוֹדוּךָ עַמִּים כֻּלָּם</strong> — "Let the peoples praise you, O God; let all the peoples give you praise!" The threefold occurrence (vv3, 5, and the implicit conclusion in v7\'s "all the ends of the earth") makes this the psalm\'s heartbeat. Between the twin refrains (vv3 and 5), the central declaration: fair judgment and guiding governance (v4) are why the nations can join the praise. The nations do not praise God despite his governance but because of it.</p>',
    "6": '<p><strong>אֶרֶץ נָתְנָה יְבוּלָהּ</strong> (<em>ʾereṣ nātĕnāh yĕbûlāh</em>, "The earth has given its harvest") — <em>yĕbûl</em>: produce, yield (the harvest as the earth\'s gift — as in Lev 26:4: "the land shall give its yield"). The harvest is God\'s sign: the agricultural blessing is the tangible evidence of divine presence. <strong>יְבָרְכֵנוּ אֱלֹהִים אֱלֹהֵינוּ</strong> (<em>yĕbārĕkênû ʾĕlōhîm ʾĕlōhênû</em>, "God, our own God, has blessed us") — the harvest interpreted: not merely natural fertility but the blessing of "our God" (<em>ʾĕlōhênû</em> — the possessive claiming of the universal God as Israel\'s own). The harvest is the sign of covenant blessing (Deut 28:12).</p>',
    "7": '<p><strong>יְבָרְכֵנוּ אֱלֹהִים</strong> (<em>yĕbārĕkênû ʾĕlōhîm</em>, "God blesses us") — the blessing declared (no longer merely prayed: the opening request "may God bless us" [v1] becomes the concluding declaration "God blesses us" [v7]). The psalm moves from petition to declaration — the prayer answered within the psalm\'s own movement. <strong>וְיִירְאוּ אֹתוֹ כָּל-אַפְסֵי-אָרֶץ</strong> (<em>wĕyîrĕʾû ʾōtô kol-ʾapsê-ʾāreṣ</em>, "and all the ends of the earth will stand in awe of him") — <em>ʾapsê-ʾāreṣ</em>: the ends/limits of the earth (as in Ps 22:27; 65:5; 67:7). <em>Yārēʾ</em>: to fear with holy awe (the fear that is not terror but reverent acknowledgment of the divine). The Aaronic blessing with which the psalm began (v1: face shining) finds its fulfillment in the universal reverence of all the earth\'s extremities — the blessing of Israel becomes the means of earth-wide divine recognition. This is the Abrahamic eschatology: one family blessed so that all families may stand in awe of the blessing-God.</p>',
  },
}

def main():
    existing = load_comm('mkt-original', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-original', 'psalms', existing)
    for ch in range(62, 68):
        print(f'  ch{ch}: {len(existing.get(str(ch), {}))} verses')
    print('Psalms 62-67 mkt-original written.')

if __name__ == '__main__':
    main()
